63	export const quote = (items: Item[], customer: Customer, contractNumber: number): number => {
64	  const componentCounts = countComponentsByType(items);
65	
66	  let policyBasePremium = 0;
67	  let itemSurcharges = 0;
68	
69	  for (const item of items) {
