112	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
113	const CLAIM_HIGH_ENCHANTMENT_RATE = 1 / 2;
114	
115	const isHighlyEnchantedForClaim = (item: Item): boolean =>
116	  hasEnchantmentAtLeast(item, CLAIM_HIGH_ENCHANTMENT_THRESHOLD);
117	
118	const findPolicyItem = (policyItems: Item[], itemType: string): Item | undefined =>
119	  policyItems.find((item) => item.type === itemType);
120	
121	const calculateEffectiveDamage = (damage: Damage, policyItems: Item[]): number => {
122	  const matchedItem = findPolicyItem(policyItems, damage.itemType);
123	  if (matchedItem && isHighlyEnchantedForClaim(matchedItem)) {
124	    return damage.amount * CLAIM_HIGH_ENCHANTMENT_RATE;
125	  }
126	  return damage.amount;
127	};
