129	export const claim = (
130	  policyItems: Item[],
131	  damages: Damage[],
132	  previousPayouts: number,
133	): ClaimResult => {
134	  const insuranceSum = policyItems.reduce(
135	    (sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0),
136	    0,
137	  );
138	  const cap = CAP_MULTIPLIER * insuranceSum;
139	  const availableCap = cap - previousPayouts;
140	
141	  const rawPayout = damages.reduce((sum, damage) => {
142	    const effectiveAmount = calculateEffectiveDamage(damage, policyItems);
143	    return sum + Math.max(0, effectiveAmount - DEDUCTIBLE);
144	  }, 0);
145	
146	  const cappedPayout = Math.min(rawPayout, availableCap);
147	  const roundedPayout = Math.floor(cappedPayout);
148	  return { payout: roundedPayout, remainingCap: availableCap - roundedPayout };
